export default {
  name: 'probe_path',
  description: 'Press a movement/action sequence step-by-step and return a compact log of coordinates, facing, map, and battle state after each step. Useful for systematic room probing and detecting blocked tiles/warps.',
  parameters: {
    type: 'object',
    properties: {
      buttons: {
        type: 'array',
        items: { type: 'string', enum: ['a','b','start','select','up','down','left','right'] },
        minItems: 1,
        maxItems: 50
      },
      hold_frames: { type: 'number', minimum: 1, maximum: 120, default: 10 },
      wait_frames: { type: 'number', minimum: 0, maximum: 600, default: 45 }
    },
    required: ['buttons']
  },
  async execute(args, ctx) {
    const hold = args.hold_frames ?? 10;
    const wait = args.wait_frames ?? 45;
    const out = [];
    for (let i = 0; i < args.buttons.length; i++) {
      const btn = args.buttons[i];
      const res = await ctx.emulator.press([btn], hold, wait);
      const s = res.state || {};
      const line = {
        step: i + 1,
        button: btn,
        location: s.location,
        map: s.map_id,
        x: s.x,
        y: s.y,
        facing: s.facing,
        battle: s.battle,
        screen_hash: res.screen_hash
      };
      out.push(line);
      ctx.log(JSON.stringify(line));
    }
    return { steps: out, final: out[out.length - 1] };
  }
};

export default {
  name: 'advance_dialog',
  description: 'Advance story dialog by pressing A repeatedly in batches, optionally with a final B press. Useful for Oak speeches, intro text, and routine NPC conversations.',
  parameters: {
    type: 'object',
    properties: {
      presses: { type: 'integer', minimum: 1, maximum: 40, default: 8 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 120, default: 6 },
      wait_frames: { type: 'integer', minimum: 0, maximum: 600, default: 20 },
      use_b_last: { type: 'boolean', default: false }
    },
    required: []
  },
  async execute(args, ctx) {
    const presses = args.presses ?? 8;
    const holdFrames = args.hold_frames ?? 6;
    const waitFrames = args.wait_frames ?? 20;
    const useBLast = args.use_b_last ?? false;

    const log = [];
    for (let i = 0; i < presses; i++) {
      const button = (useBLast && i === presses - 1) ? 'b' : 'a';
      const res = await ctx.emulator.press([button], holdFrames, waitFrames);
      const s = res.state || {};
      log.push({
        step: i + 1,
        button,
        map: s.map_name,
        map_id: s.map_id,
        x: s.x,
        y: s.y,
        battle: s.battle_type || s.in_battle || false,
        party_count: s.party?.length
      });
      ctx.log(`step ${i + 1}: ${button} -> ${s.map_name || s.map_id} (${s.x},${s.y}) battle=${s.battle_type || s.in_battle || false}`);
    }
    return { log };
  }
};

export default {
  name: 'early_battle_mash',
  description: 'Mash A through simple early-game wild/trainer battles and post-battle text, stopping when battle flag clears or batch limit is reached.',
  parameters: {
    type: 'object',
    properties: {
      batches: { type: 'integer', minimum: 1, maximum: 20, default: 6 },
      presses_per_batch: { type: 'integer', minimum: 1, maximum: 20, default: 6 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 120, default: 6 },
      wait_frames: { type: 'integer', minimum: 0, maximum: 600, default: 18 }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const batches = args.batches ?? 6;
    const pressesPerBatch = args.presses_per_batch ?? 6;
    const holdFrames = args.hold_frames ?? 6;
    const waitFrames = args.wait_frames ?? 18;

    const log = [];
    let last;
    for (let i = 0; i < batches; i++) {
      const buttons = Array.from({ length: pressesPerBatch }, () => 'a');
      last = await ctx.emulator.press(buttons, holdFrames, waitFrames);
      const s = last.state || {};
      const party = s.party || [];
      log.push({
        batch: i + 1,
        battle: !!s.battle,
        map: s.map_name || s.location || s.map || null,
        coords: s.position ? [s.position.x, s.position.y] : (typeof s.x === 'number' && typeof s.y === 'number' ? [s.x, s.y] : null),
        top_party: party[0] ? { name: party[0].species || party[0].name, level: party[0].level, hp: party[0].hp, max_hp: party[0].max_hp } : null
      });
      if (!s.battle) break;
    }
    return { ...last, log };
  }
};

export default {
  name: 'service_desk_probe',
  description: 'Move through likely service-counter tiles, press A from a chosen facing at each stop, then tap B a few times to clear text safely. Useful for Nurse Joy / shop-counter scanning without accidental long A-mash loops.',
  parameters: {
    type: 'object',
    properties: {
      moves: {
        type: 'array',
        items: { type: 'string', enum: ['up','down','left','right'] },
        description: 'Movement buttons to press one at a time before each interaction test.'
      },
      interact_facing: {
        type: 'string',
        enum: ['up','down','left','right'],
        description: 'Direction to face immediately before pressing A.',
        default: 'up'
      },
      hold_frames: {
        type: 'number',
        default: 10
      },
      wait_frames: {
        type: 'number',
        default: 30
      },
      clear_b_presses: {
        type: 'number',
        default: 3,
        description: 'How many single B presses to use after each A interaction attempt.'
      }
    },
    required: ['moves']
  },
  async execute(args, ctx) {
    const moves = args.moves || [];
    const interactFacing = args.interact_facing || 'up';
    const hold = args.hold_frames ?? 10;
    const wait = args.wait_frames ?? 30;
    const clearB = args.clear_b_presses ?? 3;
    const log = [];

    const snap = async (label) => {
      const res = await ctx.emulator.frame();
      const s = res.state || {};
      log.push({
        label,
        map: s.map_name || s.map || null,
        x: s.x ?? null,
        y: s.y ?? null,
        facing: s.facing ?? null,
        battle: s.battle_flag ?? s.in_battle ?? null,
        screen_hash: res.screen_hash || null
      });
    };

    await snap('start');
    for (let i = 0; i < moves.length; i++) {
      const mv = moves[i];
      await ctx.emulator.press([mv], hold, wait);
      await snap(`move_${i+1}_${mv}`);
      if (interactFacing !== mv) {
        await ctx.emulator.press([interactFacing], hold, wait);
        await snap(`face_${i+1}_${interactFacing}`);
      }
      await ctx.emulator.press(['a'], 6, 20);
      await snap(`a_${i+1}`);
      for (let j = 0; j < clearB; j++) {
        await ctx.emulator.press(['b'], 6, 20);
        await snap(`b_${i+1}_${j+1}`);
      }
    }
    ctx.log(`service_desk_probe completed ${moves.length} probes`);
    return { ok: true, probes: moves.length, log };
  }
};

export default {
  name: 'flee_wild_battle',
  description: 'Attempt to run from a simple wild battle by opening RUN (down, right, A), then mash through the result text until battle clears or batch limit is reached.',
  parameters: {
    type: 'object',
    properties: {
      attempts: { type: 'integer', minimum: 1, maximum: 8, default: 3 },
      clear_presses: { type: 'integer', minimum: 1, maximum: 20, default: 6 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 120, default: 6 },
      wait_frames: { type: 'integer', minimum: 0, maximum: 600, default: 18 }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const attempts = args?.attempts ?? 3;
    const clearPresses = args?.clear_presses ?? 6;
    const hold = args?.hold_frames ?? 6;
    const wait = args?.wait_frames ?? 18;

    const log = [];
    let last = await ctx.emulator.frame();
    log.push({ step: 'start', battle: last.state?.battle?.in_battle ?? last.state?.in_battle ?? null, screen_hash: last.screen_hash });

    for (let i = 0; i < attempts; i++) {
      last = await ctx.emulator.press(['down', 'right', 'a'], hold, wait);
      const inBattleAfterRunInput = last.state?.battle?.in_battle ?? last.state?.in_battle ?? null;
      log.push({ step: `run_input_${i + 1}`, battle: inBattleAfterRunInput, screen_hash: last.screen_hash });

      for (let j = 0; j < clearPresses; j++) {
        last = await ctx.emulator.press(['a'], hold, wait);
        const inBattle = last.state?.battle?.in_battle ?? last.state?.in_battle ?? null;
        log.push({ step: `clear_${i + 1}_${j + 1}`, battle: inBattle, screen_hash: last.screen_hash });
        if (inBattle === false) {
          return { ok: true, escaped: true, log, state: last.state, screen_hash: last.screen_hash };
        }
      }
    }

    return {
      ok: true,
      escaped: (last.state?.battle?.in_battle ?? last.state?.in_battle ?? null) === false,
      log,
      state: last.state,
      screen_hash: last.screen_hash
    };
  }
};

export default {
  name: 'walk_path_until_event',
  description: 'Follow a planned button path step-by-step, logging map/coords/facing after each step and stopping early if a battle starts or the map changes. Useful for executing known overworld routes without overshooting into grass or past warps.',
  parameters: {
    type: 'object',
    properties: {
      buttons: {
        type: 'array',
        items: { type: 'string', enum: ['a','b','start','select','up','down','left','right'] },
        minItems: 1,
        maxItems: 100
      },
      hold_frames: { type: 'number', minimum: 1, maximum: 120, default: 10 },
      wait_frames: { type: 'number', minimum: 0, maximum: 600, default: 45 },
      stop_on_battle: { type: 'boolean', default: true },
      stop_on_map_change: { type: 'boolean', default: true }
    },
    required: ['buttons']
  },
  async execute(args, ctx) {
    const hold = args.hold_frames ?? 10;
    const wait = args.wait_frames ?? 45;
    const stopOnBattle = args.stop_on_battle ?? true;
    const stopOnMapChange = args.stop_on_map_change ?? true;

    const start = await ctx.emulator.frame();
    const startState = start.state || {};
    const startMap = startState.map_id;
    const log = [];

    for (let i = 0; i < args.buttons.length; i++) {
      const button = args.buttons[i];
      const res = await ctx.emulator.press([button], hold, wait);
      const s = res.state || {};
      const row = {
        step: i + 1,
        button,
        map_id: s.map_id,
        map: s.map_name,
        x: s.x,
        y: s.y,
        facing: s.facing,
        battle: !!s.battle
      };
      log.push(row);
      ctx.log(JSON.stringify(row));

      if (stopOnBattle && s.battle) {
        return {
          stopped: true,
          reason: 'battle',
          start: { map_id: startMap, map: startState.map_name, x: startState.x, y: startState.y, facing: startState.facing },
          steps_executed: i + 1,
          log,
          final_state: s,
          screen_hash: res.screen_hash
        };
      }

      if (stopOnMapChange && startMap != null && s.map_id !== startMap) {
        return {
          stopped: true,
          reason: 'map_change',
          start: { map_id: startMap, map: startState.map_name, x: startState.x, y: startState.y, facing: startState.facing },
          steps_executed: i + 1,
          log,
          final_state: s,
          screen_hash: res.screen_hash
        };
      }
    }

    const finalState = log.length ? log[log.length - 1] : null;
    return {
      stopped: false,
      reason: 'completed',
      start: { map_id: startMap, map: startState.map_name, x: startState.x, y: startState.y, facing: startState.facing },
      steps_executed: log.length,
      log,
      final_state: finalState
    };
  }
};

export default {
  name: 'clear_battle_text',
  description: 'Press A in batches to clear battle/result/level-up text until the battle flag drops or a batch limit is reached.',
  parameters: {
    type: 'object',
    properties: {
      batches: { type: 'integer', minimum: 1, maximum: 20, default: 6 },
      presses_per_batch: { type: 'integer', minimum: 1, maximum: 20, default: 6 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 120, default: 6 },
      wait_frames: { type: 'integer', minimum: 0, maximum: 600, default: 18 }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const batches = args.batches ?? 6;
    const pressesPerBatch = args.presses_per_batch ?? 6;
    const holdFrames = args.hold_frames ?? 6;
    const waitFrames = args.wait_frames ?? 18;

    const out = [];
    let state = await ctx.frame();
    out.push({ step: 'start', battle: state.state?.battle_type ?? state.state?.battle ?? null, screen_hash: state.screen_hash });

    for (let i = 0; i < batches; i++) {
      state = await ctx.frame();
      const battle = state.state?.battle_type ?? state.state?.battle ?? null;
      if (!battle || battle === 'none' || battle === 0) {
        out.push({ step: `stopped_before_batch_${i+1}`, battle, screen_hash: state.screen_hash });
        return { ok: true, stopped: 'battle_cleared', log: out, state: state.state, screen_hash: state.screen_hash };
      }
      const buttons = Array.from({ length: pressesPerBatch }, () => 'a');
      state = await ctx.emulator.press(buttons, holdFrames, waitFrames);
      out.push({ step: `batch_${i+1}`, battle: state.state?.battle_type ?? state.state?.battle ?? null, screen_hash: state.screen_hash });
    }

    state = await ctx.frame();
    return { ok: true, stopped: 'batch_limit', log: out, state: state.state, screen_hash: state.screen_hash };
  }
};

export default {
  name: 'clear_battle_text_safe',
  description: 'Press A in batches to clear battle/result/level-up text until battle ends or a batch limit is reached. Avoids frame APIs and relies only on returned state.',
  parameters: {
    type: 'object',
    properties: {
      batches: { type: 'integer', minimum: 1, maximum: 30, default: 8 },
      presses_per_batch: { type: 'integer', minimum: 1, maximum: 20, default: 6 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 120, default: 6 },
      wait_frames: { type: 'integer', minimum: 0, maximum: 600, default: 18 }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const batches = args.batches ?? 8;
    const pressesPerBatch = args.presses_per_batch ?? 6;
    const holdFrames = args.hold_frames ?? 6;
    const waitFrames = args.wait_frames ?? 18;

    const logs = [];
    let last = null;

    for (let i = 0; i < batches; i++) {
      last = await ctx.emulator.press(Array(pressesPerBatch).fill('a'), holdFrames, waitFrames);
      const state = last?.state ?? {};
      const battle = state?.battle ?? null;
      const loc = state?.location ?? null;
      const x = state?.x ?? state?.coords?.x ?? null;
      const y = state?.y ?? state?.coords?.y ?? null;
      logs.push({ batch: i + 1, battle, location: loc, x, y, screen_hash: last?.screen_hash ?? null });
      ctx.log(`batch ${i + 1}: battle=${battle} loc=${loc} x=${x} y=${y}`);
      if (battle === 'none' || battle === 0 || battle === false || battle == null) {
        return { ok: true, stopped_reason: 'battle_cleared_or_not_in_battle', logs, last_state: state };
      }
    }

    return { ok: true, stopped_reason: 'batch_limit_reached', logs, last_state: last?.state ?? null };
  }
};

export default {
  name: 'wild_run_recover',
  description: 'Try to recover from messy wild-battle substates by backing out with B, then attempting common RUN selections and clearing the escape text until battle ends or attempts are exhausted.',
  parameters: {
    type: 'object',
    properties: {
      attempts: { type: 'integer', minimum: 1, maximum: 8, default: 4 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 120, default: 6 },
      wait_frames: { type: 'integer', minimum: 0, maximum: 600, default: 18 },
      clear_presses: { type: 'integer', minimum: 1, maximum: 20, default: 4 }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const attempts = args.attempts ?? 4;
    const hold = args.hold_frames ?? 6;
    const wait = args.wait_frames ?? 18;
    const clearPresses = args.clear_presses ?? 4;

    const log = [];
    const patterns = [
      ['b', 'down', 'a'],
      ['b', 'right', 'a'],
      ['b', 'down', 'right', 'a'],
      ['b', 'b', 'down', 'a'],
      ['b', 'b', 'right', 'a'],
      ['b', 'b', 'down', 'right', 'a']
    ];

    let last;
    for (let i = 0; i < attempts; i++) {
      const pattern = patterns[i % patterns.length];
      last = await ctx.emulator.press(pattern, hold, wait);
      log.push({ phase: 'attempt', i: i + 1, pattern, battle: last.state?.battle });
      if (!last.state?.battle) return { ok: true, escaped: true, log, state: last.state, screen_hash: last.screen_hash };

      last = await ctx.emulator.press(Array(clearPresses).fill('a'), hold, wait);
      log.push({ phase: 'clear', i: i + 1, presses: clearPresses, battle: last.state?.battle });
      if (!last.state?.battle) return { ok: true, escaped: true, log, state: last.state, screen_hash: last.screen_hash };
    }

    return { ok: false, escaped: false, log, state: last?.state, screen_hash: last?.screen_hash };
  }
};

export default {
  name: 'paced_battle_progress',
  description: 'Advance slow early-game battle text with a cautious cadence: wait, then single A presses, stopping if the battle ends or a command/menu state appears to have returned.',
  parameters: {
    type: 'object',
    properties: {
      cycles: { type: 'integer', minimum: 1, maximum: 20, default: 6 },
      wait_frames: { type: 'integer', minimum: 1, maximum: 240, default: 90 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 60, default: 6 },
      post_wait_frames: { type: 'integer', minimum: 0, maximum: 240, default: 24 }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const cycles = args.cycles ?? 6;
    const waitFrames = args.wait_frames ?? 90;
    const holdFrames = args.hold_frames ?? 6;
    const postWaitFrames = args.post_wait_frames ?? 24;

    const log = [];
    let last = await ctx.emulator.frame();
    log.push({ step: 'start', battle: last.state?.battle });

    for (let i = 0; i < cycles; i++) {
      if (last.state?.battle === 'none') {
        log.push({ step: 'battle_cleared_before_cycle', cycle: i });
        break;
      }

      last = await ctx.emulator.tick(waitFrames);
      log.push({ step: 'wait', cycle: i + 1, battle: last.state?.battle, text: last.state?.textbox_id ?? null });
      if (last.state?.battle === 'none') {
        log.push({ step: 'battle_cleared_after_wait', cycle: i + 1 });
        break;
      }

      last = await ctx.emulator.press(['a'], holdFrames, postWaitFrames);
      log.push({ step: 'a_press', cycle: i + 1, battle: last.state?.battle, text: last.state?.textbox_id ?? null });
      if (last.state?.battle === 'none') {
        log.push({ step: 'battle_cleared_after_a', cycle: i + 1 });
        break;
      }
    }

    return { state: last.state, screen_hash: last.screen_hash, log };
  }
};

export default {
  name: 'route2_to_forest_approach',
  description: 'From the standard Viridian north-exit landing on Route 2, follow the known safe overworld route into the gatehouse and out to the north-side forest-approach pocket, stopping early if a battle starts or an unexpected map appears.',
  parameters: {
    type: 'object',
    properties: {
      hold_frames: { type: 'number', default: 10 },
      wait_frames: { type: 'number', default: 45 },
      stop_on_battle: { type: 'boolean', default: true }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const hold = args.hold_frames ?? 10;
    const wait = args.wait_frames ?? 45;
    const stopOnBattle = args.stop_on_battle ?? true;

    const segments = [
      { label: 'route2_start_to_upper_left', buttons: ['up','up','up','up','up','up','up','up','up','up','up','up','up','up','left','left','left','left','up','up','up','up','up','up','up','up','up','up','up'] },
      { label: 'enter_gatehouse', buttons: ['left','left','left','left','up'] },
      { label: 'gatehouse_to_north_exit', buttons: ['up','up','right','right','up'] }
    ];

    const log = [];
    for (const seg of segments) {
      const res = await ctx.emulator.press(seg.buttons, hold, wait);
      const s = res.state || {};
      log.push({
        segment: seg.label,
        map: s.map_name || s.map || null,
        x: s.x ?? null,
        y: s.y ?? null,
        battle: s.battle_type || s.battle || null,
        screen_hash: res.screen_hash
      });
      if (stopOnBattle && s.battle_type && s.battle_type !== 'none') {
        ctx.log(`Stopped during ${seg.label}: battle started.`);
        return { ok: true, stopped: 'battle', log, state: s };
      }
    }

    const finalState = log.length ? log[log.length - 1].state : undefined;
    return { ok: true, stopped: null, log };
  }
};

export default {
  name: 'route2_start_to_gatehouse_south',
  description: 'From the standard Viridian north-exit landing on Route 2 around (7,71), follow the verified stepwise route to the south door of the Viridian Forest gatehouse, stopping early if a battle starts or the map changes.',
  parameters: {
    type: 'object',
    properties: {
      hold_frames: { type: 'number', default: 10 },
      wait_frames: { type: 'number', default: 45 },
      stop_on_battle: { type: 'boolean', default: true }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const hold = args.hold_frames ?? 10;
    const wait = args.wait_frames ?? 45;
    const stopOnBattle = args.stop_on_battle ?? true;

    const route = [
      ...Array(14).fill('up'),    // (7,71) -> (7,57)
      ...Array(4).fill('left'),   // -> (3,57)
      ...Array(9).fill('up'),     // -> (3,48)
      ...Array(5).fill('right'),  // -> (8,48)
      ...Array(2).fill('up'),     // -> (8,46)
      ...Array(5).fill('left'),   // -> (3,46)
      ...Array(2).fill('up')      // -> (3,44)
    ];

    const log = [];
    let last = null;
    for (let i = 0; i < route.length; i++) {
      const button = route[i];
      const res = await ctx.emulator.press([button], hold, wait);
      last = res;
      const s = res.state || {};
      log.push({
        step: i + 1,
        button,
        map: s.map_name || s.map || null,
        x: s.x ?? null,
        y: s.y ?? null,
        battle: s.battle_type || s.battle || null
      });
      if (stopOnBattle && s.battle_type && s.battle_type !== 'none') {
        ctx.log(`Stopped on battle after step ${i + 1}`);
        return { stopped: 'battle', log, state: s };
      }
      if (s.map_name && s.map_name !== 'Route 2') {
        ctx.log(`Stopped on map change to ${s.map_name} after step ${i + 1}`);
        return { stopped: 'map_change', log, state: s };
      }
    }
    return { stopped: 'completed', log, state: last?.state || null };
  }
};

export default {
  name: 'early_wild_run_opening',
  description: 'Cautiously escape an opening wild battle by advancing intro text with waits, then selecting RUN explicitly; useful for slow Route 2 Weedle/Kakuna/Pidgey starts.',
  parameters: {
    type: 'object',
    properties: {
      cycles: { type: 'integer', minimum: 1, maximum: 12, default: 6 },
      intro_wait_frames: { type: 'integer', minimum: 1, maximum: 240, default: 48 },
      hold_frames: { type: 'integer', minimum: 1, maximum: 60, default: 6 },
      wait_frames: { type: 'integer', minimum: 0, maximum: 180, default: 18 },
      post_escape_wait_frames: { type: 'integer', minimum: 0, maximum: 240, default: 72 }
    },
    additionalProperties: false
  },
  async execute(args, ctx) {
    const cycles = args.cycles ?? 6;
    const introWait = args.intro_wait_frames ?? 48;
    const hold = args.hold_frames ?? 6;
    const wait = args.wait_frames ?? 18;
    const postEscape = args.post_escape_wait_frames ?? 72;

    const out = [];
    const battleOn = (s) => {
      const b = s?.battle;
      return !(b === 'none' || b === null || b === undefined || b === false);
    };

    let res = await ctx.emulator.tick(introWait);
    out.push({ step: 'initial_wait', battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
    if (!battleOn(res.state)) return { ok: true, escaped: true, log: out, state: res.state };

    for (let i = 0; i < cycles; i++) {
      res = await ctx.emulator.press(['a'], hold, wait);
      out.push({ step: `advance_${i+1}`, battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
      if (!battleOn(res.state)) {
        await ctx.emulator.tick(postEscape);
        return { ok: true, escaped: true, log: out, state: res.state };
      }

      res = await ctx.emulator.tick(introWait);
      out.push({ step: `settle_${i+1}`, battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
      if (!battleOn(res.state)) return { ok: true, escaped: true, log: out, state: res.state };

      res = await ctx.emulator.press(['down','right','a'], hold, wait);
      out.push({ step: `run_attempt_${i+1}`, battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
      if (!battleOn(res.state)) {
        res = await ctx.emulator.tick(postEscape);
        out.push({ step: `post_escape_wait_${i+1}`, battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
        return { ok: true, escaped: !battleOn(res.state), log: out, state: res.state };
      }

      res = await ctx.emulator.press(['a'], hold, wait);
      out.push({ step: `clear_after_run_${i+1}`, battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
      if (!battleOn(res.state)) {
        res = await ctx.emulator.tick(postEscape);
        out.push({ step: `post_clear_wait_${i+1}`, battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
        return { ok: true, escaped: !battleOn(res.state), log: out, state: res.state };
      }

      res = await ctx.emulator.press(['b'], hold, wait);
      out.push({ step: `backout_${i+1}`, battle: res.state?.battle, map: res.state?.map, x: res.state?.x, y: res.state?.y });
      if (!battleOn(res.state)) return { ok: true, escaped: true, log: out, state: res.state };
    }

    return { ok: false, escaped: false, log: out, state: res.state };
  }
};
